  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { buildWorkspaceOverview, buildProjectContext, buildTaskContext } from "./context-builder";
  3→import { searchEntitiesByEmbedding, type SearchEntityKind } from "../graph/queries";
  4→import { createEmbeddingVector } from "../graph/embeddings";
  5→import type { ContextPacket, TaskContextPacket, WorkspaceOverview } from "./types";
  6→
  7→// ---------------------------------------------------------------------------
  8→// Types
  9→// ---------------------------------------------------------------------------
 10→
 11→export type IntentContextInput = {
 12→  intent: string;
 13→  cwd?: string;
 14→  paths?: string[];
 15→};
 16→
 17→export type IntentContextResult =
 18→  | { level: "task"; data: TaskContextPacket }
 19→  | { level: "project"; data: ContextPacket }
 20→  | { level: "workspace"; data: WorkspaceOverview };
 21→
 22→type ProjectRow = {
 23→  id: RecordId<"project", string>;
 24→  name: string;
 25→  status: string;
 26→  description?: string;
 27→};
 28→
 29→// ---------------------------------------------------------------------------
 30→// Resolution
 31→// ---------------------------------------------------------------------------
 32→
 33→export async function resolveIntentContext(input: {
 34→  surreal: Surreal;
 35→  embeddingModel: Parameters<typeof createEmbeddingVector>[0];
 36→  embeddingDimension: number;
 37→  workspaceRecord: RecordId<"workspace", string>;
 38→  workspaceName: string;
 39→  intent: string;
 40→  cwd?: string;
 41→  paths?: string[];
 42→}): Promise<IntentContextResult> {
 43→  const { surreal, embeddingModel, embeddingDimension, workspaceRecord, workspaceName, intent } = input;
 44→
 45→  // Step 1: Explicit entity references in intent text
 46→  const explicitTask = extractEntityRef(intent, "task");
 47→  if (explicitTask) {
 48→    try {
 49→      const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId: explicitTask });
 50→      return { level: "task", data };
 51→    } catch {
 52→      // Task not found — fall through to other strategies
 53→    }
 54→  }
 55→
 56→  const explicitProject = extractEntityRef(intent, "project");
 57→  if (explicitProject) {
 58→    try {
 59→      const projectRecord = new RecordId("project", explicitProject);
 60→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
 61→      return { level: "project", data };
 62→    } catch {
 63→      // Project not found — fall through
 64→    }
 65→  }
 66→
 67→  // Step 2: Single-project shortcut
 68→  const projects = await listWorkspaceProjects(surreal, workspaceRecord);
 69→  if (projects.length === 1) {
 70→    const data = await buildProjectContext({
 71→      surreal,
 72→      workspaceRecord,
 73→      workspaceName,
 74→      projectRecord: projects[0].id,
 75→    });
 76→    return { level: "project", data };
 77→  }
 78→
 79→  // Step 3: Vector search — embed intent, match against all entities
 80→  const queryEmbedding = await createEmbeddingVector(embeddingModel, intent, embeddingDimension);
 81→  if (queryEmbedding) {
 82→    const results = await searchEntitiesByEmbedding({
 83→      surreal,
 84→      workspaceRecord,
 85→      queryEmbedding,
 86→      limit: 5,
 87→    });
 88→
 89→    if (results.length > 0 && results[0].score > 0.3) {
 90→      const top = results[0];
 91→
 92→      if (top.kind === "task") {
 93→        const taskId = top.id.includes(":") ? top.id.split(":")[1] : top.id;
 94→        try {
 95→          const data = await buildTaskContext({ surreal, workspaceRecord, workspaceName, taskId });
 96→          return { level: "task", data };
 97→        } catch {
 98→          // Fall through
 99→        }
100→      }
101→
102→      // For project/feature matches, or task fallback: resolve to project context
103→      const projectRecord = await resolveProjectFromMatch(surreal, top);
104→      if (projectRecord) {
105→        const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord });
106→        return { level: "project", data };
107→      }
108→    }
109→  }
110→
111→  // Step 4: Path matching — match directory names against project names
112→  const allPaths = [...(input.paths ?? [])];
113→  if (input.cwd) allPaths.push(input.cwd);
114→
115→  if (allPaths.length > 0 && projects.length > 0) {
116→    const matched = matchPathToProject(allPaths, projects);
117→    if (matched) {
118→      const data = await buildProjectContext({ surreal, workspaceRecord, workspaceName, projectRecord: matched });
119→      return { level: "project", data };
120→    }
121→  }
122→
123→  // Step 5: Fallback — workspace overview
124→  const data = await buildWorkspaceOverview({ surreal, workspaceRecord, workspaceName });
125→  return { level: "workspace", data };
126→}
127→
128→// ---------------------------------------------------------------------------
129→// Helpers
130→// ---------------------------------------------------------------------------
131→
132→/** Extract explicit entity reference like `task:abc123` or `project:def456` from text */
133→function extractEntityRef(text: string, entityType: string): string | undefined {
134→  const pattern = new RegExp(`\\b${entityType}:([a-zA-Z0-9_-]+)`, "i");
135→  const match = text.match(pattern);
136→  return match ? match[1] : undefined;
137→}
138→
139→/** List all projects in a workspace */
140→async function listWorkspaceProjects(
141→  surreal: Surreal,
142→  workspaceRecord: RecordId<"workspace", string>,
143→): Promise<ProjectRow[]> {
144→  const [rows] = await surreal
145→    .query<[ProjectRow[]]>(
146→      `SELECT id, name, status, description FROM project
147→       WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);`,
148→      { workspace: workspaceRecord },
149→    )
150→    .collect<[ProjectRow[]]>();
151→  return rows;
152→}
153→
154→/** Resolve a search match to a project RecordId */
155→async function resolveProjectFromMatch(
156→  surreal: Surreal,
157→  match: { id: string; kind: SearchEntityKind },
158→): Promise<RecordId<"project", string> | undefined> {
159→  if (match.kind === "project") {
160→    const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
161→    return new RecordId("project", rawId);
162→  }
163→
164→  // For task/decision/question/suggestion: find project via belongs_to
165→  // For feature: find project via has_feature (reverse)
166→  const rawId = match.id.includes(":") ? match.id.split(":")[1] : match.id;
167→  const table = match.kind;
168→  const entityRecord = new RecordId(table, rawId);
169→
170→  if (match.kind === "feature") {
171→    const [rows] = await surreal
172→      .query<[Array<{ in: RecordId<"project", string> }>]>(
173→        `SELECT \`in\` FROM has_feature WHERE out = $entity LIMIT 1;`,
174→        { entity: entityRecord },
175→      )
176→      .collect<[Array<{ in: RecordId<"project", string> }>]>();
177→    return rows.length > 0 ? rows[0].in : undefined;
178→  }
179→
180→  // task, decision, question, suggestion → belongs_to → project
181→  const [rows] = await surreal
182→    .query<[Array<{ out: RecordId<"project", string> }>]>(
183→      `SELECT out FROM belongs_to WHERE \`in\` = $entity AND record::tb(out) = "project" LIMIT 1;`,
184→      { entity: entityRecord },
185→    )
186→    .collect<[Array<{ out: RecordId<"project", string> }>]>();
187→  return rows.length > 0 ? rows[0].out : undefined;
188→}
189→
190→/** Match directory paths against project names using normalized token overlap */
191→function matchPathToProject(
192→  paths: string[],
193→  projects: ProjectRow[],
194→): RecordId<"project", string> | undefined {
195→  const pathTokens = new Set<string>();
196→  for (const p of paths) {
197→    for (const segment of p.split("/").filter(Boolean)) {
198→      for (const token of segment.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/)) {
199→        if (token.length > 2) pathTokens.add(token);
200→      }
201→    }
202→  }
203→
204→  if (pathTokens.size === 0) return undefined;
205→
206→  let bestProject: ProjectRow | undefined;
207→  let bestOverlap = 0;
208→
209→  for (const project of projects) {
210→    const nameTokens = new Set(
211→      project.name.toLowerCase().replace(/[^a-z0-9]/g, " ").split(/\s+/).filter((t) => t.length > 2),
212→    );
213→    let overlap = 0;
214→    for (const token of nameTokens) {
215→      if (pathTokens.has(token)) overlap++;
216→    }
217→    if (overlap > bestOverlap) {
218→      bestOverlap = overlap;
219→      bestProject = project;
220→    }
221→  }
222→
223→  return bestProject ? bestProject.id : undefined;
224→}
