304→// ---------------------------------------------------------------------------
305→
306→type CreateSessionInput = {
307→  surreal: Surreal;
308→  shellExec: ShellExec;
309→  brainBaseUrl: string;
310→  workspaceId: string;
311→  taskId: string;
312→  spawnAgent?: SpawnAgentFn;
313→  validateAssignment: (
314→    surreal: Surreal,
315→    workspaceId: string,
316→    taskId: string,
317→  ) => Promise<AssignmentResult>;
318→  createAgentSession: (input: {
319→    surreal: Surreal;
320→    agent: string;
321→    workspaceRecord: RecordId<"workspace", string>;
322→    taskId?: string;
323→  }) => Promise<{ session_id: string }>;
324→};
325→
326→export async function createOrchestratorSession(
327→  input: CreateSessionInput,
328→): Promise<OrchestratorSessionResult> {
329→  // 1. Validate assignment eligibility
330→  const assignmentResult = await input.validateAssignment(
331→    input.surreal,
332→    input.workspaceId,
333→    input.taskId,
334→  );
335→
336→  if (!assignmentResult.ok) {
337→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
338→  }
339→
340→  const { validation } = assignmentResult;
341→  const taskSlug = `${slugFromTitle(validation.title)}-${Date.now()}`;
342→  const repoRoot = validation.repoPath;
343→
344→  // 2. Create worktree
345→  const worktreeResult = await createWorktree(
346→    input.shellExec,
347→    repoRoot,
348→    taskSlug,
349→  );
350→
351→  if (!worktreeResult.ok) {
352→    return {
353→      ok: false,
354→      error: worktreeError(worktreeResult.error.message),
355→    };
356→  }
357→
358→  const { branchName, worktreePath } = worktreeResult.value;
359→
360→  // 3. Create agent_session record
361→  const { session_id: agentSessionId } = await input.createAgentSession({
362→    surreal: input.surreal,
363→    agent: "claude-agent-sdk",
364→    workspaceRecord: validation.workspaceRecord,
365→    taskId: input.taskId,
366→  });
367→
368→  const streamId = generateStreamId(agentSessionId);
369→
370→  // 4. Build config and spawn agent
371→  const agentSpawnConfig: AgentSpawnConfig = {
372→    prompt: `/brain-start-task ${input.taskId}`,
373→    workDir: worktreePath,
374→    workspaceId: input.workspaceId,
375→    brainBaseUrl: input.brainBaseUrl,
376→  };
377→
378→  const spawnFn = input.spawnAgent ?? defaultSpawnAgent;
379→  let handle: AgentHandle;
380→  try {
381→    handle = spawnFn(agentSpawnConfig);
382→  } catch (err) {
383→    // Rollback: remove worktree and delete agent_session on spawn failure
384→    await removeWorktree(input.shellExec, repoRoot, branchName);
385→    const sessionRecord = new RecordId("agent_session", agentSessionId);
386→    await input.surreal.delete(sessionRecord);
387→    return {
388→      ok: false,
389→      error: worktreeError(`Failed to spawn agent: ${err instanceof Error ? err.message : String(err)}`),
390→    };
391→  }
392→
393→  // 5. Register handle for later abort
394→  handleRegistry.set(agentSessionId, handle);
395→
396→  // 6. Update agent_session with orchestrator fields
397→  const sessionRecord = new RecordId("agent_session", agentSessionId);
398→  await input.surreal.update(sessionRecord).merge({
399→    orchestrator_status: "spawning" as OrchestratorStatus,
400→    worktree_branch: branchName,
401→    worktree_path: worktreePath,
402→    stream_id: streamId,
403→  });
404→
405→  return {
406→    ok: true,
407→    value: {
408→      agentSessionId,
409→      streamId,
410→      worktreeBranch: branchName,
411→    },
412→  };
413→}
414→
415→// Default spawn -- placeholder for production use
416→function defaultSpawnAgent(
417→  _config: AgentSpawnConfig,
418→): AgentHandle {
419→  throw new Error(
420→    "spawnAgent not provided -- must be injected for production use",
421→  );
422→}
