460→
461→type AbortSessionInput = {
462→  surreal: Surreal;
463→  shellExec: ShellExec;
464→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
465→  sessionId: string;
466→  endAgentSession: (input: {
467→    surreal: Surreal;
468→    workspaceRecord: RecordId<"workspace", string>;
469→    sessionId: string;
470→    summary: string;
471→  }) => Promise<{ session_id: string; ended: boolean }>;
472→};
473→
474→export async function abortOrchestratorSession(
475→  input: AbortSessionInput,
476→): Promise<AbortSessionResult> {
477→  const lookup = await lookupSession(input.surreal, input.sessionId);
478→  if (!lookup.ok) {
479→    return { ok: false, error: lookup.error };
480→  }
481→  const { session, record: sessionRecord } = lookup;
482→
483→  // 1. Abort the agent process if handle exists
484→  const handle = handleRegistry.get(input.sessionId);
485→  if (handle) {
486→    handle.abort();
487→    handleRegistry.delete(input.sessionId);
488→  }
489→
490→  // 2. Update orchestrator_status to aborted
491→  await input.surreal.update(sessionRecord).merge({
492→    orchestrator_status: "aborted" as OrchestratorStatus,
493→  });
494→
495→  const workspaceRecord = requireWorkspace(session, input.sessionId);
496→
497→  // 3. Remove worktree if branch name exists
498→  if (session.worktree_branch) {
499→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
500→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
501→  }
502→
503→  // 4. Return task to ready
504→  if (session.task_id) {
505→    await input.surreal.update(session.task_id).merge({
506→      status: "ready",
507→      updated_at: new Date(),
508→    });
509→  }
510→
511→  // 5. End the agent session
512→  await input.endAgentSession({
513→    surreal: input.surreal,
514→    workspaceRecord,
515→    sessionId: input.sessionId,
516→    summary: "Session aborted",
517→  });
518→
519→  return {
520→    ok: true,
521→    value: {
522→      aborted: true,
523→      sessionId: input.sessionId,
524→    },
525→  };
526→}
