544→export async function acceptOrchestratorSession(
545→  input: AcceptSessionInput,
546→): Promise<AcceptSessionResult> {
547→  const lookup = await lookupSession(input.surreal, input.sessionId);
548→  if (!lookup.ok) {
549→    return { ok: false, error: lookup.error };
550→  }
551→  const { session, record: sessionRecord, status } = lookup;
552→
553→  if (!ACCEPTABLE_STATUSES.has(status)) {
554→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
555→  }
556→
557→  const workspaceRecord = requireWorkspace(session, input.sessionId);
558→
559→  // 1. Update orchestrator_status to completed
560→  await input.surreal.update(sessionRecord).merge({
561→    orchestrator_status: "completed" as OrchestratorStatus,
562→  });
563→
564→  // 2. Clean up handle registry
565→  handleRegistry.delete(input.sessionId);
566→
567→  // 4. End the agent session
568→  await input.endAgentSession({
569→    surreal: input.surreal,
570→    workspaceRecord,
571→    sessionId: input.sessionId,
572→    summary: input.summary,
573→  });
574→
575→  return {
576→    ok: true,
577→    value: {
578→      accepted: true,
579→      sessionId: input.sessionId,
580→    },
581→  };
582→}
