610→// getOrchestratorReview
611→// ---------------------------------------------------------------------------
612→
613→type GetReviewInput = {
614→  surreal: Surreal;
615→  sessionId: string;
616→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
617→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
618→  getTaskTitle: (taskId: string) => Promise<string>;
619→};
620→
621→export async function getOrchestratorReview(
622→  input: GetReviewInput,
623→): Promise<ReviewResult> {
624→  const lookup = await lookupSession(input.surreal, input.sessionId);
625→  if (!lookup.ok) {
626→    return { ok: false, error: lookup.error };
627→  }
628→  const { session, status } = lookup;
629→
630→  if (status === "aborted") {
631→    return { ok: false, error: sessionAborted(input.sessionId) };
632→  }
633→
634→  if (!REVIEWABLE_STATUSES.has(status)) {
635→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
636→  }
637→
638→  // Get diff from the branch
639→  const branchName = session.worktree_branch ?? "";
640→  const workspaceRecord = requireWorkspace(session, input.sessionId);
641→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
642→  const diffResult = await input.getDiff(repoRoot, branchName);
643→
644→  const diff = diffResult.ok
645→    ? diffResult.value
646→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
647→
648→  // Get task title
649→  const taskId = session.task_id ? session.task_id.id : "";
650→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
651→
652→  return {
653→    ok: true,
654→    value: {
655→      taskTitle,
656→      diff,
657→      session: {
658→        orchestratorStatus: status,
659→        ...pickDefined({
660→          worktreeBranch: session.worktree_branch,
661→          startedAt: session.started_at,
662→          lastEventAt: session.last_event_at,
663→        }),
664→      },
665→    },
666→  };
667→}
