669→// ---------------------------------------------------------------------------
670→// rejectOrchestratorSession
671→// ---------------------------------------------------------------------------
672→
673→type RejectSessionInput = {
674→  surreal: Surreal;
675→  sessionId: string;
676→  feedback: string;
677→};
678→
679→export async function rejectOrchestratorSession(
680→  input: RejectSessionInput,
681→): Promise<RejectSessionResult> {
682→  const lookup = await lookupSession(input.surreal, input.sessionId);
683→  if (!lookup.ok) {
684→    return { ok: false, error: lookup.error };
685→  }
686→  const { session, record: sessionRecord, status } = lookup;
687→
688→  if (!REJECTABLE_STATUSES.has(status)) {
689→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
690→  }
691→
692→  // 1. Update session status to active (agent resumes work)
693→  await input.surreal.update(sessionRecord).merge({
694→    orchestrator_status: "active" as OrchestratorStatus,
695→    last_feedback: input.feedback,
696→  });
697→
698→  // 2. Return task to in_progress
699→  if (session.task_id) {
700→    await input.surreal.update(session.task_id).merge({
701→      status: "in_progress",
702→      updated_at: new Date(),
703→    });
704→  }
705→
706→  return {
707→    ok: true,
708→    value: {
709→      rejected: true,
710→      continuing: true,
711→    },
712→  };
713→}
714→
715→// ---------------------------------------------------------------------------
716→// sendSessionPrompt
717→// ---------------------------------------------------------------------------
718→
719→type SendPromptInput = {
720→  surreal: Surreal;
721→  sessionId: string;
722→  text: string;
723→};
724→
725→export async function sendSessionPrompt(
726→  input: SendPromptInput,
727→): Promise<PromptSessionResult> {
728→  const lookup = await lookupSession(input.surreal, input.sessionId);
729→  if (!lookup.ok) {
730→    return { ok: false, error: lookup.error };
731→  }
732→  const { status } = lookup;
733→
734→  if (!PROMPTABLE_STATUSES.has(status)) {
735→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
736→  }
737→
738→  // The Claude Agent SDK uses a single query() call per conversation.
739→  // Follow-up prompts are not supported in this model.
740→  return {
741→    ok: false,
742→    error: {
743→      code: "SESSION_ERROR",
744→      message: `Follow-up prompts are not supported with the Agent SDK. Session ${input.sessionId} runs a single query() conversation.`,
745→      httpStatus: 409,
746→    },
747→  };
748→}
